python3 - <<'PY'
from Registry import Registry
from datetime import datetime, timedelta
import struct, os
base='/home/ctfplayer/ctf_files/extracted'
sys=Registry.Registry(os.path.join(base,'SYSTEM'))
soft=Registry.Registry(os.path.join(base,'SOFTWARE'))
sam=Registry.Registry(os.path.join(base,'SAM'))
sel=sys.open('Select')
current=sel.value('Current').value()
ccs='ControlSet%03d'%current
print('CCS',ccs)
# hostname
for path in [ccs+'\\Control\\ComputerName\\ComputerName', ccs+'\\Services\\Tcpip\\Parameters']:
    k=sys.open(path)
    print('\n['+path+']')
    for v in k.values():
        print(v.name(),repr(v.value()))
# os info
path=r'Microsoft\Windows NT\CurrentVersion'
k=soft.open(path)
print('\n['+path+']')
for name in ['ProductName','EditionID','ReleaseId','CurrentBuild','CurrentBuildNumber','CurrentVersion','DisplayVersion','RegisteredOwner','RegisteredOrganization','InstallDate','InstallTime','ProductId','PathName','SystemRoot']: 
    try: print(name,repr(k.value(name).value()))
    except: pass
# profile list
path=r'Microsoft\Windows NT\CurrentVersion\ProfileList'
k=soft.open(path)
print('\n[ProfileList]')
for sk in k.subkeys():
    print('SID',sk.name())
    for v in sk.values():
        print(' ',v.name(),repr(v.value()))
# winlogon
for path in [r'Microsoft\Windows NT\CurrentVersion\Winlogon', r'Microsoft\Windows\CurrentVersion\Run', r'Microsoft\Windows\CurrentVersion\RunOnce']:
    try:
        k=soft.open(path)
        print('\n['+path+']')
        for v in k.values():
            print(v.name(),repr(v.value()))
    except Exception as e:
        pass
# uninstall names
for path in [r'Microsoft\Windows\CurrentVersion\Uninstall', r'WOW6432Node\Microsoft\Windows\CurrentVersion\Uninstall']:
    try:
        k=soft.open(path)
        print('\n['+path+'] first few')
        for sk in k.subkeys()[:20]:
            try: dn=sk.value('DisplayName').value()
            except: dn=''
            print(sk.name(),repr(dn))
    except: pass
# network interfaces
path=ccs+r'\Services\Tcpip\Parameters\Interfaces'
k=sys.open(path)
print('\n[Interfaces]')
for sk in k.subkeys():
    print('IF',sk.name())
    for v in sk.values():
        print(' ',v.name(),repr(v.value()))
# mounted devices / usbstor names only
for path in [ccs+r'\Enum\USBSTOR', ccs+r'\Services', ccs+r'\Control\TimeZoneInformation']:
    try:
        k=sys.open(path)
        print('\n['+path+']')
        if path.endswith('Services'):
            for sk in k.subkeys()[:10]: print(sk.name())
        else:
            for sk in k.subkeys():
                print('sub',sk.name())
                for sk2 in sk.subkeys():
                    print(' sub2',sk2.name())
    except Exception as e:
        if 'TimeZoneInformation' in path:
            k=sys.open(path)
            for v in k.values(): print(v.name(),repr(v.value()))
# SAM names
print('\n[SAM users]')
for sk in sam.open(r'SAM\Domains\Account\Users\Names').subkeys():
    print(sk.name(),sk.timestamp())
PY

